const Header = ({ cartCount, user, screen, setScreen, onLogout }) => {
  return (
    <header className="site-header">
      <div className="container nav-shell">
        <button className="brand" type="button" onClick={() => setScreen('home')}>
          <span className="brand-mark">RK</span>
          <span>
            <strong>Razmena knjiga</strong>
            <small>Fakultet tehnickih nauka u Novom Sadu</small>
          </span>
        </button>

        <nav className="main-nav" aria-label="Navigacija">
          <button className={screen === 'home' ? 'active' : ''} type="button" onClick={() => setScreen('home')}>
            Pocetna
          </button>
          <button className={screen === 'cart' ? 'active' : ''} type="button" onClick={() => setScreen('cart')}>
            Korpa <span className="badge">{cartCount}</span>
          </button>
          {user ? (
            <button className={screen === 'profile' ? 'active' : ''} type="button" onClick={() => setScreen('profile')}>
              {user.name}
            </button>
          ) : (
            <button className={screen === 'login' ? 'active' : ''} type="button" onClick={() => setScreen('login')}>
              Prijava
            </button>
          )}
          {user?.isAdmin && (
            <button className={screen === 'admin' ? 'active' : ''} type="button" onClick={() => setScreen('admin')}>
              Admin
            </button>
          )}
          {user && (
            <button type="button" onClick={onLogout}>
              Odjava
            </button>
          )}
        </nav>
      </div>
    </header>
  );
};

export default Header;
